21: /*! \file instrument.hpp
22:     \brief Abstract instrument class
23: */
24: 
25: #ifndef quantlib_instrument_hpp
26: #define quantlib_instrument_hpp
27: 
28: #include <ql/patterns/lazyobject.hpp>
29: #include <ql/pricingengine.hpp>
30: #include <ql/utilities/null.hpp>
31: #include <ql/time/date.hpp>
32: #include <ql/any.hpp>
33: #include <map>
34: #include <string>
35: 
36: namespace QuantLib {
37: 
38:     //! Abstract instrument class
39:     /*! This class is purely abstract and defines the interface of concrete
40:         instruments which will be derived from this one.
41: 
42:         \test observability of class instances is checked.
43:     */
44:     class Instrument : public LazyObject {
45:       public:
46:         class results;
47:         Instrument();
48:         //! \name Inspectors
49:         //@{
50: 
51:         //! returns the net present value of the instrument.
52:         Real NPV() const;
53:         //! returns the error estimate on the NPV when available.
54:         Real errorEstimate() const;
55:         //! returns the date the net present value refers to.
56:         const Date& valuationDate() const;
57: 
58:         const ext::shared_ptr<PricingEngine>& pricingEngine() const;
59:         //! returns any additional result returned by the pricing engine.
60:         template <typename T> T result(const std::string& tag) const;
61:         //! returns all additional result returned by the pricing engine.
62:         const std::map<std::string, ext::any>& additionalResults() const;
63: 
64:         //! returns whether the instrument might have value greater than zero.
65:         virtual bool isExpired() const = 0;
66:         //@}
67:         //! \name Modifiers
68:         //@{
69:         //! set the pricing engine to be used.
70:         /*! \warning calling this method will have no effects in
71:                      case the <b>performCalculation</b> method
72:                      was overridden in a derived class.
73:         */
74:         void setPricingEngine(const ext::shared_ptr<PricingEngine>&);
75:         //@}
76:         /*! When a derived argument structure is defined for an
77:             instrument, this method should be overridden to fill
78:             it. This is mandatory in case a pricing engine is used.
79:         */
80:         virtual void setupArguments(PricingEngine::arguments*) const;
81:         /*! When a derived result structure is defined for an
82:             instrument, this method should be overridden to read from
83:             it. This is mandatory in case a pricing engine is used.
84:         */
85:         virtual void fetchResults(const PricingEngine::results*) const;
86:       protected:
87:         //! \name Calculations
88:         //@{
89:         void calculate() const override;
90:         /*! This method must leave the instrument in a consistent
91:             state when the expiration condition is met.
92:         */
93:         virtual void setupExpired() const;
94:         /*! In case a pricing engine is <b>not</b> used, this
95:             method must be overridden to perform the actual
96:             calculations and set any needed results. In case
97:             a pricing engine is used, the default implementation
98:             can be used.
99:         */
100:         void performCalculations() const override;
101:         //@}
102:         /*! \name Results
103:             The value of this attribute and any other that derived
104:             classes might declare must be set during calculation.
105:         */
106:         //@{
107:         mutable Real NPV_, errorEstimate_;
108:         mutable Date valuationDate_;
109:         mutable std::map<std::string, ext::any> additionalResults_;
110:         //@}
111:         ext::shared_ptr<PricingEngine> engine_;
112:     };
113: 
114:     class Instrument::results : public virtual PricingEngine::results {
115:       public:
116:         void reset() override {
117:             value = errorEstimate = Null<Real>();
118:             valuationDate = Date();
119:             additionalResults.clear();
120:         }
121:         Real value;
122:         Real errorEstimate;
123:         Date valuationDate;
124:         std::map<std::string, ext::any> additionalResults;
125:     };
126: 
127: 
128:     // inline definitions
129: 
130:     inline void Instrument::calculate() const {
131:         if (!calculated_) {
132:             if (isExpired()) {
133:                 setupExpired();
134:                 calculated_ = true;
135:             } else {
136:                 LazyObject::calculate();
137:             }
138:         }
139:     }
140: 
141:     inline void Instrument::setupExpired() const {
142:         NPV_ = errorEstimate_ = 0.0;
143:         valuationDate_ = Date();
144:         additionalResults_.clear();
145:     }
146: 
147:     inline void Instrument::performCalculations() const {
148:         QL_REQUIRE(engine_, "null pricing engine");
149:         engine_->reset();
150:         setupArguments(engine_->getArguments());
151:         engine_->getArguments()->validate();
152:         engine_->calculate();
153:         fetchResults(engine_->getResults());
154:     }
155: 
156:     inline void Instrument::fetchResults(
157:                                       const PricingEngine::results* r) const {
158:         const auto* results = dynamic_cast<const Instrument::results*>(r);
159:         QL_ENSURE(results != nullptr, "no results returned from pricing engine");
160: 
161:         NPV_ = results->value;
162:         errorEstimate_ = results->errorEstimate;
163:         valuationDate_ = results->valuationDate;
164: 
165:         additionalResults_ = results->additionalResults;
166:     }
167: 
168:     inline Real Instrument::NPV() const {
169:         calculate();
170:         QL_REQUIRE(NPV_ != Null<Real>(), "NPV not provided");
171:         return NPV_;
172:     }
173: 
174:     inline Real Instrument::errorEstimate() const {
175:         calculate();
176:         QL_REQUIRE(errorEstimate_ != Null<Real>(),
177:                    "error estimate not provided");
178:         return errorEstimate_;
179:     }
180: 
181:     inline const Date& Instrument::valuationDate() const {
182:         calculate();
183:         QL_REQUIRE(valuationDate_ != Date(),
184:                    "valuation date not provided");
185:         return valuationDate_;
186:     }
187: 
188:     inline const ext::shared_ptr<PricingEngine>& Instrument::pricingEngine() const {
189:         return engine_;
190:     }
191: 
192:     template <class T>
193:     inline T Instrument::result(const std::string& tag) const {
194:         calculate();
195:         auto value =
196:             additionalResults_.find(tag);
197:         QL_REQUIRE(value != additionalResults_.end(),
198:                    tag << " not provided");
199:         return ext::any_cast<T>(value->second);
200:     }
201: 
202:     inline const std::map<std::string, ext::any>&
203:     Instrument::additionalResults() const {
204:         calculate();
205:         return additionalResults_;
206:     }
207: 
208: }
209: 
210: #endif
