22:     \brief General-purpose Monte Carlo model
23: */
24: 
25: #ifndef quantlib_montecarlo_model_hpp
26: #define quantlib_montecarlo_model_hpp
27: 
28: #include <ql/math/statistics/statistics.hpp>
